#include<bits/stdc++.h>
#define hash myhash
using namespace std;
typedef unsigned long long ull;
ull h[1000010],base[1000010];
int n;
char s[1000010];
ull hash(int l,int r)
{
    return h[r]-h[l-1]*base[r-l+1];
}
int main()
{
    scanf("%d%s",&n,s+1);
    base[0]=1;
    for(int i=1;i<=n;i++)
    {
        h[i]=h[i-1]*131+s[i];
        base[i]=base[i-1]*131;
    }
    for(int i=1;i<=n;i++)
    {
        ull tmp=hash(1,i);
        bool flag=true;
        for(int l=1,r=i;l<=n;l+=i,r+=i)
        {
            if(r>n)
            {
                if(hash(l,n)!=hash(1,n-l+1))
                {
                    flag=false;
                    break;
                }
                continue;
            }
            if(hash(l,r)!=tmp)
            {
                flag=false;
                break;
            }
        }
        if(flag)
        {
            printf("%d",i);
            return 0;
        }
    }
    return 0;
}
